  final FirebaseAuth _auth;
  final FirebaseFirestore _firestore;
  final IsarNoteStore _isarNoteStore;
  final ExternalSyncService _externalSync;
  final NoteEventBus _noteEventBus;
  final AiClassifierRouter _aiRouter;

  StreamSubscription<String>? _noteSavedSubscription;
  final Set<String> _inFlightNoteIds = {};
  bool _sweepRunning = false;

  void start() {
    // Sweep existing pending notes shortly after startup
    Future.delayed(const Duration(seconds: 2), _sweepPendingOnce);
    // Listen for new saves
    _noteSavedSubscription ??= _noteEventBus.onNoteSaved.listen((noteId) {
      Future.delayed(const Duration(milliseconds: 300), () {
        unawaited(processNoteById(noteId));
      });
    });
  }

  Future<void> flushPendingQueue() => _sweepPendingOnce();

  void dispose() {
    _noteSavedSubscription?.cancel();
    _noteSavedSubscription = null;
  }

  Future<void> _sweepPendingOnce() async {
    if (_sweepRunning) return;
    _sweepRunning = true;
    try {
      final pending = await _isarNoteStore.getPendingAiNotes();
      if (pending.isEmpty) return;
      debugPrint('[AiProcessingService] Sweeping ${pending.length} pending notes');
      // Process in batches of 2 to avoid hammering Gemini
      for (var i = 0; i < pending.length; i += 2) {
        final chunk = pending.sublist(i, (i + 2).clamp(0, pending.length));
        await Future.wait(chunk.map((n) => processNoteById(n.noteId)));
        if (i + 2 < pending.length) {
          await Future<void>.delayed(const Duration(milliseconds: 500));
        }
      }
    } catch (e, st) {
      debugPrint('[AiProcessingService] sweep error: $e');
      debugPrintStack(stackTrace: st);
    } finally {
      _sweepRunning = false;
    }
  }

  Future<void> processNoteById(String noteId) async {
    final id = noteId.trim();
    if (id.isEmpty || _inFlightNoteIds.contains(id)) return;

    _inFlightNoteIds.add(id);
    try {
      final note = await _isarNoteStore.getByNoteId(id);
      if (note == null) {
        debugPrint('[AiProcessingService] Note not found: $id');
        return;
      }
      if (note.status != NoteStatus.pendingAi) {
        debugPrint('[AiProcessingService] Skipping $id — status=${note.status.name}');
        return;
      }

      debugPrint('[AiProcessingService] Classifying: $id');

      // ── Run AI on the main isolate so plugin state & env vars are accessible ─
      // (google_generative_ai is stateless; safe to call here)
      final result = await _aiRouter.classify(note.rawTranscript);

      debugPrint('[AiProcessingService] Classified: $id → '
          'cat=${result.category.name} pri=${result.priority.name} '
          'model=${result.model} fallback=${result.wasFallback}');

      final now = DateTime.now();
      final activeNote = note.copyWith(
        title: result.title,
        category: result.category,
        priority: result.priority,
        extractedDate: result.extractedDate,
        clearExtractedDate: result.extractedDate == null,
        cleanBody: result.cleanBody,
        aiModel: result.model,
        status: NoteStatus.active,
        updatedAt: now,
        syncedAt: now,
      );

      await _isarNoteStore.put(activeNote);
      debugPrint('[AiProcessingService] Saved to Isar: $id');

      // ── Notify UI ──────────────────────────────────────────────────────────
      try {
        sl<CaptureUiController>().notifyExternalRecordingSaved(
          title: activeNote.title,
          category: activeNote.category,
          model: activeNote.aiModel.trim().isNotEmpty ? activeNote.aiModel : 'AI',
          noteId: activeNote.noteId,
        );
      } catch (_) {}

      try {
        await sl<OverlayNotifier>().notifyNativeSaved(
          activeNote.title,
          activeNote.category,
        );
      } catch (_) {}

      // ── Background: Firestore + external sync (fire-and-forget) ───────────
      unawaited(_syncAll(activeNote));
    } catch (e, st) {
      debugPrint('[AiProcessingService] Error processing $id: $e');
      debugPrintStack(stackTrace: st);
      // Mark as active with fallback so it won't be retried forever
      try {
        final note = await _isarNoteStore.getByNoteId(id);
        if (note != null && note.status == NoteStatus.pendingAi) {
          await _isarNoteStore.put(note.copyWith(
            status: NoteStatus.active,
            aiModel: 'error-fallback',
            updatedAt: DateTime.now(),
          ));
        }
      } catch (_) {}
    } finally {
      _inFlightNoteIds.remove(id);
    }
  }

  // ── Sync helpers ──────────────────────────────────────────────────────────

  Future<void> _syncAll(Note note) async {
    await Future.wait([
      _syncToFirestore(note),
      _syncToExternal(note),
    ]);
  }

  Future<void> _syncToExternal(Note note) async {
    try {
      final changed = await _externalSync.syncNoteToExternal(note);
      if (changed != null && changed.noteId == note.noteId) {
        // External sync updated gtaskId or gcalEventId — persist those back
        await _isarNoteStore.put(changed);
        await _syncToFirestore(changed);
      }
    } catch (e) {
      debugPrint('[AiProcessingService] external sync error for ${note.noteId}: $e');
    }
  }

  Future<bool> _syncToFirestore(Note note) async {
    var user = _auth.currentUser;
    if (user == null) {
      try {
        user = await _auth
            .authStateChanges()
            .firstWhere((u) => u != null, orElse: () => null as User?)
            .timeout(const Duration(seconds: 3));
      } catch (_) {}
    }

    final uid = user?.uid ?? note.uid;
    if (uid.isEmpty || uid == 'local_anonymous') {
      debugPrint('[AiProcessingService] Firestore sync skipped: not authenticated');
      return false;
    }

    try {
      await _firestore
          .collection('users')
          .doc(uid)
          .collection('notes')
          .doc(note.noteId)
          .set(note.toFirestoreJson(), SetOptions(merge: true));
      return true;
    } catch (e) {
      debugPrint('[AiProcessingService] Firestore error: $e');
      return false;
    }
  }
}

import 'dart:convert';

import 'package:google_generative_ai/google_generative_ai.dart';
import 'package:wishperlog/core/config/app_env.dart';
import 'package:wishperlog/shared/models/enums.dart';

class GeminiClassificationResult {
  const GeminiClassificationResult({
    required this.title,
    required this.category,
    required this.priority,
    required this.extractedDate,
    required this.cleanBody,
    required this.model,
    required this.wasFallback,
  });

  final String title;
  final NoteCategory category;
  final NotePriority priority;
  final DateTime? extractedDate;
  final String cleanBody;
  final String model;
  final bool wasFallback;
}

class GeminiNoteClassifier {
  GeminiNoteClassifier({String? apiKey, GenerativeModel? model})
      : _apiKey = apiKey ?? AppEnv.geminiApiKey,
        _providedModel = model;

  // ─────────────────────────────────────────────────────────────────────────
  // SYSTEM PROMPT — v3
  // Goals:
  //   1. Actively correct STT mispronunciations / grammar before saving.
  //   2. Strict JSON-only output.
  //   3. Crystal-clear disambiguation rules to eliminate mis-categorisation.
  // ─────────────────────────────────────────────────────────────────────────
  static const String systemPrompt = r'''
You are an intelligent voice-note post-processor. You receive raw speech-to-text output which may contain mispronunciations, homophones, run-on sentences, filler words, and grammatical errors. Your job is to:
  A) Intelligently correct the text (see clean_body rules below).
  B) Classify it into a structured JSON object.

════════════════════════════════
OUTPUT — ONE raw JSON object only.
No markdown, no backticks, no prose.
First byte must be `{`, last byte `}`.
════════════════════════════════
{
  "title":          "<string: 3–9 words, imperative or noun-phrase>",
  "clean_body":     "<string: corrected note text>",
  "category":       "<string: tasks|reminders|ideas|follow-up|journal|general>",
  "priority":       "<string: high|medium|low>",
  "extracted_date": "<string YYYY-MM-DD | null>"
}

━━━ FIELD RULES ━━━━━━━━━━━━━━━

title
  • 3–9 words in input language.
  • Start with an action verb OR the main subject noun.
  • No trailing punctuation. No filler openings ("Note about", "Remind me to").
  • ✓ "Call dentist Friday" ✓ "Landing page hero section" ✓ "Mom birthday gift"

clean_body  ← ACTIVE CORRECTION REQUIRED
  • Fix ALL of the following from raw STT output:
    – Homophones / mispronunciations  (e.g. "meting" → "meeting", "contrack" → "contract")
    – Filler words  (e.g. "um", "uh", "like", "you know", "basically") — remove unless semantically relevant.
    – Repeated words  (e.g. "the the", "call call") — deduplicate.
    – Run-on fragments joined by "and" or "so" — break into separate sentences.
    – Missing capitalisation at sentence starts.
    – Obvious missing articles (a/an/the) only when unambiguous.
  • DO NOT: translate, summarise, add new context, change names, change numbers.
  • Preserve: tone, slang, emoji, technical jargon, proper nouns (even if unusual).

category — choose exactly ONE:
  "tasks"     → Clear action the user must complete (has a done state).
                Signals: "do", "buy", "fix", "send", "finish", "complete", "review".
  "reminders" → Time/location-sensitive nudge. Has a WHEN or WHERE.
                Signals: time words (tomorrow, 3pm, next week), "remind me", "don't forget", "when I get to".
  "ideas"     → Creative/exploratory thought. No defined done-state.
                Signals: "what if", "idea", "maybe we could", speculative language.
  "follow-up" → Requires action involving another person/system after an interaction.
                Signals: "follow up", "check with", "ask", "waiting for", "reply to", named person + verb.
  "journal"   → Personal reflection, emotion, memory, observation. Pure internal state.
                Signals: feelings, past tense reflections, "I feel", "I noticed", "today was".
  "general"   → Facts, references, credentials, recipes, addresses, code snippets, anything else.

  PRIORITY RULES (applied in order — first match wins):
  1. Both action AND explicit time → "reminders"
  2. Involves specific named person needing response → "follow-up"
  3. Pure internal feeling → "journal"
  4. Clear verb+object with done state → "tasks"
  5. Speculative/creative → "ideas"
  6. Otherwise → "general"

priority — choose exactly ONE:
  "high"   → Urgent. Signals: "asap", "urgent", "today", "by EOD", "deadline", "critical", date ≤ 3 days.
  "medium" → Default. Important but not immediately urgent.
  "low"    → Background. Signals: "eventually", "someday", "when I have time", "nice to have".

extracted_date
  • Return ISO 8601 "YYYY-MM-DD" if the note implies an action date.
  • Resolve relative dates ("tomorrow" = today+1, "next Monday", "in 3 days").
  • If vague ("soon", "later", "someday") → null.
  • Never invent a date. Null if uncertain.
  • Use today as the reference date (the note was captured right now).

════════════════════════════════
FALLBACK (use when input < 3 meaningful words or pure noise):
{"title":"Untitled note","clean_body":"","category":"general","priority":"low","extracted_date":null}
════════════════════════════════
''';

  final String _apiKey;
  final GenerativeModel? _providedModel;

  bool get isConfigured => _providedModel != null || _apiKey.isNotEmpty;

  Future<GeminiClassificationResult> classify(String rawTranscript) async {
    final text = rawTranscript.trim();
    if (text.isEmpty) return _fallback(rawTranscript, model: 'none');
    if (!isConfigured) {
      debugLog('[GeminiClassifier] API key not configured — using fallback');
      return _fallback(rawTranscript, model: 'offline-fallback');
    }

    final model = _providedModel ??
        GenerativeModel(
          model: 'gemini-2.5-flash-lite-preview-06-17',
          apiKey: _apiKey,
          generationConfig: GenerationConfig(
            temperature: 0.1,   // Low temperature for consistent structured output
            topK: 1,
            topP: 0.95,
            maxOutputTokens: 512,
          ),
        );

    const maxAttempts = 3;
    for (var attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        final response = await model.generateContent([
          Content.system(systemPrompt),
          Content.text('Today is ${_todayString()}.\nRaw STT input:\n$text'),
        ]).timeout(const Duration(seconds: 15));

        final payload = response.text?.trim();
        if (payload == null || payload.isEmpty) {
          debugLog('[GeminiClassifier] Empty response on attempt $attempt');
          continue;
        }

        final result = _parseOrFallback(
          rawTranscript: rawTranscript,
          payload: payload,
          model: 'gemini-2.5-flash-lite',
        );

        if (!result.wasFallback) {
          debugLog('[GeminiClassifier] OK: cat=${result.category.name} '
              'pri=${result.priority.name} title="${result.title}"');
        }
        return result;
      } catch (e) {
        final err = e.toString();
        debugLog('[GeminiClassifier] attempt=$attempt error: $err');
        final isRateLimit = err.contains('429') ||
            err.contains('quota') ||
            err.contains('RESOURCE_EXHAUSTED');
        if (isRateLimit && attempt < maxAttempts - 1) {
          await Future<void>.delayed(Duration(seconds: (attempt + 1) * 5));
          continue;
        }
        // Non-rate-limit error — bail immediately
        return _fallback(rawTranscript, model: 'gemini-2.5-flash-lite');
      }
    }
    return _fallback(rawTranscript, model: 'gemini-2.5-flash-lite');
  }

  // ── Parsing ────────────────────────────────────────────────────────────────

  GeminiClassificationResult _parseOrFallback({
    required String rawTranscript,
    required String payload,
    required String model,
  }) {
    try {
      var clean = payload
          .replaceAll(RegExp(r'^```[a-z]*\n?', multiLine: true), '')
          .replaceAll(RegExp(r'```$', multiLine: true), '')
          .trim();

      final start = clean.indexOf('{');
      final end   = clean.lastIndexOf('}');
      if (start == -1 || end == -1 || end <= start) {
        debugLog('[GeminiClassifier] No JSON object found in payload');
        return _fallback(rawTranscript, model: model);
      }
      clean = clean.substring(start, end + 1);

      final json = jsonDecode(clean) as Map<String, dynamic>;

      final title   = (json['title']      as String? ?? '').trim();
      final body    = (json['clean_body'] as String? ?? rawTranscript).trim();
      final catStr  = (json['category']   as String? ?? 'general').toLowerCase().trim();
      final priStr  = (json['priority']   as String? ?? 'medium').toLowerCase().trim();
      final dateStr =  json['extracted_date'] as String?;

      return GeminiClassificationResult(
        title:         title.isEmpty ? _quickTitle(rawTranscript) : title,
        category:      _parseCategory(catStr),
        priority:      _parsePriority(priStr),
        extractedDate: _parseDate(dateStr),
        cleanBody:     body.isEmpty ? rawTranscript : body,
        model:         model,
        wasFallback:   false,
      );
    } catch (e) {
      debugLog('[GeminiClassifier] JSON parse error: $e');
      return _fallback(rawTranscript, model: model);
    }
  }

  GeminiClassificationResult _fallback(String raw, {required String model}) =>
      GeminiClassificationResult(
        title:         _quickTitle(raw),
        category:      NoteCategory.general,
        priority:      NotePriority.medium,
        extractedDate: null,
        cleanBody:     raw,
        model:         model,
        wasFallback:   true,
      );

  // ── Helpers ────────────────────────────────────────────────────────────────

  String _quickTitle(String text) {
    final line = text.replaceAll('\n', ' ').trim();
    return line.length <= 72 ? line : '${line.substring(0, 72).trimRight()}…';
  }

  String _todayString() {
    final now = DateTime.now();
    return '${now.year}-${now.month.toString().padLeft(2, '0')}-'
        '${now.day.toString().padLeft(2, '0')}';
  }

  NoteCategory _parseCategory(String s) => switch (s) {
    'tasks'                                    => NoteCategory.tasks,
    'reminders'                                => NoteCategory.reminders,
    'ideas'                                    => NoteCategory.ideas,
    'follow-up' || 'follow_up' || 'followup'  => NoteCategory.followUp,
    'journal'                                  => NoteCategory.journal,
    _                                          => NoteCategory.general,
  };

  NotePriority _parsePriority(String s) => switch (s) {
    'high' => NotePriority.high,
    'low'  => NotePriority.low,
    _      => NotePriority.medium,
  };

  DateTime? _parseDate(String? s) {
    if (s == null || s.isEmpty || s == 'null') return null;
    try { return DateTime.parse(s); } catch (_) { return null; }
  }

  void debugLog(String msg) => debugPrint(msg);
}

import 'dart:convert';

import 'package:flutter/foundation.dart';
import 'package:http/http.dart' as http;
import 'package:wishperlog/core/config/app_env.dart';
import 'package:wishperlog/features/ai/data/gemini_note_classifier.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note_helpers.dart';

/// Calls Groq Chat API (OpenAI-compatible) to classify notes.
/// Uses llama-3.3-70b-versatile by default.
class GroqNoteClassifier {
  static const _baseUrl = 'https://api.groq.com/openai/v1/chat/completions';
  static const _model = 'llama-3.3-70b-versatile';

  final String _apiKey;

  GroqNoteClassifier({String? apiKey}) : _apiKey = apiKey ?? AppEnv.groqApiKey;

  bool get isConfigured => _apiKey.isNotEmpty;

  Future<GeminiClassificationResult?> classify(String rawTranscript) async {
    if (!isConfigured || rawTranscript.trim().isEmpty) return null;

    try {
      final response = await http.post(
        Uri.parse(_baseUrl),
        headers: {
          'Authorization': 'Bearer $_apiKey',
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'model': _model,
          'messages': [
            {'role': 'system', 'content': GeminiNoteClassifier.systemPrompt},
            {'role': 'user', 'content': 'Raw input: ${rawTranscript.trim()}'},
          ],
          'temperature': 0.3,
          'max_tokens': 512,
        }),
      ).timeout(const Duration(seconds: 15));

      if (response.statusCode != 200) {
        debugPrint('[GroqClassifier] API error ${response.statusCode}: ${response.body}');
        return null;
      }

      final body = jsonDecode(response.body) as Map<String, dynamic>;
      final content = (body['choices'] as List?)?.first?['message']?['content'] as String?;
      if (content == null || content.isEmpty) return null;

      return _parse(rawTranscript, content.trim());
    } catch (e) {
      debugPrint('[GroqClassifier] classify error: $e');
      return null;
    }
  }

  GeminiClassificationResult? _parse(String raw, String payload) {
    try {
      final noFence = payload
          .replaceAll('```json', '')
          .replaceAll('```', '')
          .trim();
      final start = noFence.indexOf('{');
      final end = noFence.lastIndexOf('}');
      if (start < 0 || end < start) return null;

      final decoded = jsonDecode(noFence.substring(start, end + 1)) as Map<String, dynamic>;
      final title = (decoded['title'] as String?)?.trim();
      final cleanBody = (decoded['clean_body'] as String?)?.trim();
      return GeminiClassificationResult(
        title: (title == null || title.isEmpty) ? _fallbackTitle(raw) : title,
        category: parseCategory((decoded['category'] as String?) ?? NoteCategory.general.name),
        priority: parsePriority((decoded['priority'] as String?) ?? NotePriority.medium.name),
        extractedDate: _parseDate(decoded['extracted_date']),
        cleanBody: (cleanBody == null || cleanBody.isEmpty) ? raw.trim() : cleanBody,
        model: 'groq/$_model',
        wasFallback: false,
      );
    } catch (_) {
      return null;
    }
  }

  DateTime? _parseDate(dynamic value) {
    if (value == null) return null;
    final raw = value.toString().trim();
    if (raw.isEmpty || raw.toLowerCase() == 'null') return null;
    return DateTime.tryParse(raw)?.toLocal();
  }

  String _fallbackTitle(String text) {
    final oneLine = text.replaceAll('\n', ' ').trim();
    if (oneLine.length <= 60) return oneLine;
    return '${oneLine.substring(0, 60).trimRight()}...';
  }
}

import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart' as auth;
import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:google_sign_in/google_sign_in.dart';
import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:wishperlog/core/config/app_env.dart';

class SignInFriendlyException implements Exception {
  const SignInFriendlyException(this.message);

  final String message;

  @override
  String toString() => message;
}

class UserRepository {
  final auth.FirebaseAuth _firebaseAuth = auth.FirebaseAuth.instance;
  final FirebaseFirestore _firestore = FirebaseFirestore.instance;
  final GoogleSignIn _googleSignIn = GoogleSignIn(
    clientId: kIsWeb
      ? (AppEnv.googleWebClientId.isEmpty ? null : AppEnv.googleWebClientId)
      : null,
  );

  Stream<auth.User?> get authStateChanges => _firebaseAuth.authStateChanges();

  Future<auth.UserCredential> signInWithGoogle() async {
    try {
      if (kIsWeb) {
        final provider = auth.GoogleAuthProvider();
        final userCredential = await _firebaseAuth.signInWithPopup(provider);
        final user = userCredential.user;
        if (user == null) {
          throw Exception('Google sign in aborted');
        }

        await _upsertUserDocument(
          firebaseUser: user,
          googleAuth: null,
        );

        return userCredential;
      }

      final GoogleSignInAccount? googleUser = await _googleSignIn.signIn();
      if (googleUser == null) {
        throw Exception('Google sign in aborted');
      }

      final GoogleSignInAuthentication googleAuth =
          await googleUser.authentication;
      final auth.AuthCredential credential = auth.GoogleAuthProvider.credential(
        accessToken: googleAuth.accessToken,
        idToken: googleAuth.idToken,
      );

      final auth.UserCredential userCredential = await _firebaseAuth
          .signInWithCredential(credential);

      await _upsertUserDocument(
        firebaseUser: userCredential.user!,
        googleAuth: googleAuth,
      );

      return userCredential;
    } on PlatformException catch (e) {
      final joined = '${e.code} ${e.message ?? ''}'.toLowerCase();
      if (joined.contains('10')) {
        throw const SignInFriendlyException(
          'Developer Error: SHA-1 mismatch. Please add your debug keystore SHA-1 to the Firebase Console and re-download google-services.json.',
        );
      }
      rethrow;
    }
  }

  Future<void> _upsertUserDocument({
    required auth.User firebaseUser,
    required GoogleSignInAuthentication? googleAuth,
  }) async {
    final prefs = await SharedPreferences.getInstance();
    final overlayX = prefs.getDouble('overlay.pos.x') ?? 0.0;
    final overlayY = prefs.getDouble('overlay.pos.y') ?? 0.0;

    final userDoc = _firestore.collection('users').doc(firebaseUser.uid);
    final docSnapshot = await userDoc.get();
    final data = {
      'uid': firebaseUser.uid,
      'email': firebaseUser.email ?? '',
      'display_name': firebaseUser.displayName ?? '',
      'google_tokens': {
        'access_token': googleAuth?.accessToken,
        'refresh_token': null,
        'expiry': null,
      },
      'telegram_chat_id': docSnapshot.data()?['telegram_chat_id'] as String?,
      'digest_time': (docSnapshot.data()?['digest_time'] as String?) ?? '09:00',
      'overlay_position': {'x': overlayX, 'y': overlayY},
      'overlay_visible': (docSnapshot.data()?['overlay_visible'] as bool?) ?? true,
      'fcm_token': (docSnapshot.data()?['fcm_token'] as String?) ?? '',
    };

    if (!docSnapshot.exists) {
      await userDoc.set({
        ...data,
        'created_at': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));
      return;
    }

    await userDoc.set(data, SetOptions(merge: true));
  }

  Future<void> signOut() async {
    await _googleSignIn.signOut();
    await _firebaseAuth.signOut();
  }

  Stream<Map<String, dynamic>?> watchCurrentUserDocument() {
    return _firebaseAuth.authStateChanges().asyncExpand((user) {
      if (user == null) {
        return Stream.value(null);
      }
      return _firestore
          .collection('users')
          .doc(user.uid)
          .snapshots()
          .map((doc) => doc.data());
    });
  }

  Future<void> updateDigestTime(String digestTime) async {
    final user = _firebaseAuth.currentUser;
    if (user == null) {
      return;
    }
    await _firestore.collection('users').doc(user.uid).set({
      'digest_time': digestTime,
      'digest_times': [digestTime],
      'timezone_offset_minutes': DateTime.now().timeZoneOffset.inMinutes,
    }, SetOptions(merge: true));
  }

  Future<void> updateDigestTimes(
    List<TimeOfDay> times, {
    List<String> utcSlots = const [],
  }) async {
    final user = _firebaseAuth.currentUser;
    if (user == null) return;
    final data = <String, dynamic>{
      'digest_times': times.map((t) =>
          '${t.hour.toString().padLeft(2, '0')}:${t.minute.toString().padLeft(2, '0')}').toList(),
      'digest_times_utc': utcSlots,
      'updated_at': FieldValue.serverTimestamp(),
    };
    await FirebaseFirestore.instance
        .collection('users')
        .doc(user.uid)
        .set(data, SetOptions(merge: true));
  }

  Future<void> updateOverlayVisibility(bool visible) async {
    final user = _firebaseAuth.currentUser;
    if (user == null) {
      return;
    }
    await _firestore.collection('users').doc(user.uid).set({
      'overlay_visible': visible,
    }, SetOptions(merge: true));
  }

  Future<void> updateTelegramChatId(String chatId) async {
    final user = _firebaseAuth.currentUser;
    if (user == null) {
      return;
    }
    final normalized = chatId.trim();
    await _firestore.collection('users').doc(user.uid).set({
      'telegram_chat_id': normalized,
    }, SetOptions(merge: true));

    final prefs = await SharedPreferences.getInstance();
    if (normalized.isEmpty) {
      await prefs.remove('telegram_chat_id');
    } else {
      await prefs.setString('telegram_chat_id', normalized);
    }
  }

  Future<void> writePendingTelegramToken({
    required String token,
    required DateTime expiresAt,
  }) async {
    final user = _firebaseAuth.currentUser;
    if (user == null || token.trim().isEmpty) {
      return;
    }

    await _firestore.collection('users').doc(user.uid).set({
      'pending_telegram': {
        'token': token.trim(),
        'expires_at': Timestamp.fromDate(expiresAt.toUtc()),
      },
    }, SetOptions(merge: true));
  }

  Future<void> clearPendingTelegramToken() async {
    final user = _firebaseAuth.currentUser;
    if (user == null) {
      return;
    }

    await _firestore.collection('users').doc(user.uid).set({
      'pending_telegram': FieldValue.delete(),
    }, SetOptions(merge: true));
  }

  Future<void> updateFcmToken(String token) async {
    final user = _firebaseAuth.currentUser;
    if (user == null || token.trim().isEmpty) {
      return;
    }
    await _firestore.collection('users').doc(user.uid).set({
      'fcm_token': token.trim(),
    }, SetOptions(merge: true));
  }

  Future<void> updateOverlayPosition({required double x, required double y}) async {
    final user = _firebaseAuth.currentUser;
    if (user == null) {
      return;
    }

    await _firestore.collection('users').doc(user.uid).set({
      'overlay_position': {'x': x, 'y': y},
    }, SetOptions(merge: true));
  }
}

import 'dart:async';
import 'dart:math';

import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:flutter/foundation.dart';
import 'package:wishperlog/core/di/injection_container.dart';
import 'package:wishperlog/core/storage/isar_note_store.dart';
import 'package:wishperlog/features/ai/data/ai_classifier_router.dart';
import 'package:wishperlog/shared/events/note_event_bus.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note.dart';

class CaptureService {
  CaptureService({
    FirebaseAuth? auth,
    FirebaseFirestore? firestore,
    IsarNoteStore? isarNoteStore,
    NoteEventBus? noteEventBus,
    AiClassifierRouter? aiRouter,
  }) : _auth = auth ?? _safeFirebaseAuth(),
       _firestore = firestore ?? _safeFirestore(),
       _isarNoteStore = isarNoteStore ?? IsarNoteStore.instance,
       _noteEventBus = noteEventBus ?? NoteEventBus.instance,
       _aiRouter =
           aiRouter ??
           (sl.isRegistered<AiClassifierRouter>()
               ? sl<AiClassifierRouter>()
               : AiClassifierRouter());

  final FirebaseAuth? _auth;
  final FirebaseFirestore? _firestore;
  final IsarNoteStore _isarNoteStore;
  final NoteEventBus _noteEventBus;
  final AiClassifierRouter _aiRouter;

  String get activeProviderName => _aiRouter.lastUsedModelName;

  static FirebaseAuth? _safeFirebaseAuth() {
    try {
      return FirebaseAuth.instance;
    } catch (_) {
      return null;
    }
  }

  static FirebaseFirestore? _safeFirestore() {
    try {
      return FirebaseFirestore.instance;
    } catch (_) {
      return null;
    }
  }

  Future<Note?> ingestRawCapture({
    required String rawTranscript,
    required CaptureSource source,
    bool syncToCloud = true,
  }) async {
    final trimmed = rawTranscript.trim();
    if (trimmed.isEmpty) return null;

    try {
      final now = DateTime.now();
      final user = _auth?.currentUser;
      final noteId = '${now.microsecondsSinceEpoch}_${Random().nextInt(1 << 20)}';

      // STEP 1: Instant local save with fallback title.
      final quickTitle = _quickTitle(trimmed);
      final initialNote = Note(
        noteId: noteId,
        uid: user?.uid ?? 'local_anonymous',
        rawTranscript: trimmed,
        title: quickTitle,
        cleanBody: trimmed,
        category: NoteCategory.general,
        priority: NotePriority.medium,
        extractedDate: null,
        createdAt: now,
        updatedAt: now,
        status: NoteStatus.pendingAi,
        aiModel: 'pending',
        gcalEventId: null,
        gtaskId: null,
        source: source,
        syncedAt: null,
      );

      await _isarNoteStore.put(initialNote);

      debugPrint('[CaptureService] Saved instantly: $noteId');

      // STEP 2: Emit saved event for immediate UI confirmation.
      _noteEventBus.emitNoteSaved(noteId);

      // STEP 3: Fire-and-forget cloud sync.
      if (syncToCloud) {
        unawaited(_syncNoteToFirestore(initialNote));
      }

      return initialNote;
    } catch (error, stackTrace) {
      debugPrint('[CaptureService] ERROR during ingestRawCapture: $error');
      debugPrintStack(stackTrace: stackTrace);
      rethrow;
    }
  }

  /// Instant local title from first 60 chars - no network, no AI.
  String _quickTitle(String text) {
    final oneLine = text.replaceAll('\n', ' ').trim();
    if (oneLine.length <= 60) return oneLine;
    return '${oneLine.substring(0, 60).trimRight()}...';
  }

  Future<void> _syncNoteToFirestore(Note note) async {
    final auth = _auth;
    final firestore = _firestore;
    if (auth == null || firestore == null) {
      debugPrint(
        '[CaptureService] Firestore sync skipped: auth or firestore null',
      );
      return;
    }

    var user = auth.currentUser;
    if (user == null) {
      try {
        user = await auth
            .authStateChanges()
            .firstWhere((u) => u != null, orElse: () => null as User?)
            .timeout(const Duration(seconds: 2));
      } catch (_) {}
    }

    if (user == null) {
      debugPrint(
        '[CaptureService] Firestore sync skipped: user not authenticated',
      );
      return;
    }

    try {
      debugPrint('[CaptureService] Syncing note to Firestore: ${note.noteId}');

      await firestore
          .collection('users')
          .doc(user.uid)
          .collection('notes')
          .doc(note.noteId)
          .set(note.toFirestoreJson(), SetOptions(merge: true));

      debugPrint(
        '[CaptureService] Successfully synced to Firestore: ${note.noteId}',
      );
    } catch (e, st) {
      debugPrint(
        '[CaptureService] ERROR syncing to Firestore: ${note.noteId}: $e',
      );
      debugPrintStack(stackTrace: st);
      // Firestore sync will be retried via existing sync flow.
    }
  }
}

