class FolderScreen extends StatefulWidget {
  const FolderScreen({required this.category, super.key});

  final NoteCategory category;

  @override
  State<FolderScreen> createState() => _FolderScreenState();
}

class _FolderScreenState extends State<FolderScreen> {
  final NoteRepository _notes = sl<NoteRepository>();

  void _goBack() {
    if (Navigator.of(context).canPop()) {
      context.pop();
      return;
    }
    context.go('/home');
  }

  @override
  Widget build(BuildContext context) {
    final secondaryText = context.textSec;

    return StreamBuilder<List<Note>>(
      stream: _notes.watchActiveByCategoryLocal(widget.category),
      builder: (context, snapshot) {
        final notes = snapshot.data ?? const <Note>[];
        return Scaffold(
          backgroundColor: Colors.transparent,
          appBar: GlassTitleBar(
            title: categoryLabel(widget.category),
            subtitle: '${notes.length} notes',
            onBack: _goBack,
            leading: Icon(
              categoryIcon(widget.category),
              size: 18,
              color: categoryColor(widget.category),
            ),
            trailing: Container(
              padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
              decoration: BoxDecoration(
                color: categoryColor(widget.category).withValues(alpha: 0.16),
                borderRadius: BorderRadius.circular(10),
              ),
              child: Text(
                '${notes.length}',
                style: TextStyle(
                  color: categoryColor(widget.category),
                  fontSize: 12,
                  fontWeight: FontWeight.w800,
                ),
              ),
            ),
          ),
          body: GlassPageBackground(
            category: widget.category,
            child: TweenAnimationBuilder<double>(
              tween: Tween(begin: 0, end: 1),
              duration: const Duration(milliseconds: 300),
              curve: Curves.easeInOut,
              builder: (context, value, child) {
                final targetTint = categoryColor(
                  widget.category,
                ).withValues(alpha: context.isDark ? 0.07 : 0.045);
                return FolderGlassTint(
                  tint: targetTint.withValues(alpha: targetTint.a * value),
                  child: child!,
                );
              },
              child: (() {
                if (snapshot.hasError) {
                  return Center(
                    child: Text(
                      'Unable to load notes right now.',
                      style: TextStyle(
                        color: secondaryText,
                        fontStyle: FontStyle.italic,
                        fontWeight: FontWeight.w500,
                        letterSpacing: 0.1,
                        fontSize: 13.5,
                      ),
                    ),
                  );
                }

                if (!snapshot.hasData &&
                    snapshot.connectionState == ConnectionState.waiting) {
                  return const Center(
                    child: CircularProgressIndicator(strokeWidth: 2),
                  );
                }

                final notes = snapshot.data ?? const <Note>[];

                if (notes.isEmpty) {
                  return ListView(
                    padding: const EdgeInsets.fromLTRB(14, 10, 14, 20),
                    children: [
                      Padding(
                        padding: const EdgeInsets.only(top: 56),
                        child: Center(
                          child: Text(
                            'No notes here yet.',
                            textAlign: TextAlign.center,
                            style: TextStyle(
                              color: secondaryText,
                              fontStyle: FontStyle.italic,
                              fontWeight: FontWeight.w500,
                              letterSpacing: 0.1,
                              fontSize: 13.5,
                            ),
                          ),
                        ),
                      ),
                    ],
                  );
                }

                return ListView.builder(
                  padding: const EdgeInsets.fromLTRB(14, 10, 14, 20),
                  itemCount: notes.length,
                  itemBuilder: (context, index) {
                    final note = notes[index];

                    return Padding(
                      padding: EdgeInsets.only(
                        bottom: index == notes.length - 1 ? 0 : 10,
                      ),
                      child: Dismissible(
                        key: ValueKey(note.noteId),
                        confirmDismiss: (direction) async {
                          if (direction == DismissDirection.startToEnd) {
                            unawaited(_notes.delete(note.noteId));
                            unawaited(HapticFeedback.lightImpact());
                            return true;
                          }

                          await _openReassignSheet(note);
                          return false;
                        },
                        background: _swipeBackground(
                          alignment: Alignment.centerLeft,
                          color: Colors.red.withValues(alpha: 0.12),
                          icon: Icons.delete_outline,
                          label: 'Delete',
                        ),
                        secondaryBackground: _swipeBackground(
                          alignment: Alignment.centerRight,
                          color: categoryColor(
                            widget.category,
                          ).withValues(alpha: 0.12),
                          icon: Icons.category_outlined,
                          label: 'Reassign',
                        ),
                        child: GlassNoteCard(
                          note: note,
                          onTap: () async {
                            await HapticFeedback.lightImpact();
                            await _openEditSheet(note);
                          },
                        ),
                      ),
                    );
                  },
                );
              })(),
            ), // closes TweenAnimationBuilder
          ), // closes GlassPageBackground
          floatingActionButton: FloatingActionButton.extended(
            onPressed: () {
              showModalBottomSheet(
                context: context,
                isScrollControlled: true,
                backgroundColor: Colors.transparent,
                builder: (_) => const QuickNoteEditor(),
              );
            },
            icon: const Icon(Icons.add),
            label: Text('New ${categoryLabel(widget.category).toLowerCase()}'),
            backgroundColor: categoryColor(widget.category),
            foregroundColor: Colors.white,
          ),
        ); // closes Scaffold
      }, // closes StreamBuilder builder
    ); // closes StreamBuilder
  }

  Widget _swipeBackground({
    required Alignment alignment,
    required Color color,
    required IconData icon,
    required String label,
  }) {
    final isLeft = alignment == Alignment.centerLeft;
    return Container(
      decoration: BoxDecoration(
        color: color,
        borderRadius: BorderRadius.circular(14),
      ),
      padding: EdgeInsets.symmetric(horizontal: isLeft ? 16 : 18),
      alignment: alignment,
      child: Row(
        mainAxisAlignment: isLeft
            ? MainAxisAlignment.start
            : MainAxisAlignment.end,
        children: [
          if (!isLeft) ...[
            Text(label, style: const TextStyle(fontWeight: FontWeight.w600)),
            const SizedBox(width: 8),
          ],
          Icon(icon, size: 18),
          if (isLeft) ...[
            const SizedBox(width: 8),
            Text(label, style: const TextStyle(fontWeight: FontWeight.w600)),
          ],
        ],
      ),
    );
  }

  Future<void> _openReassignSheet(Note note) async {
    await showModalBottomSheet<void>(
      context: context,
      backgroundColor: Colors.transparent,
      builder: (context) {
        return Padding(
          padding: const EdgeInsets.fromLTRB(14, 0, 14, 14),
          child: GlassPane(
            level: 1,
            radius: 20,
            padding: const EdgeInsets.fromLTRB(12, 12, 12, 12),
            child: Wrap(
              spacing: 8,
              runSpacing: 8,
              children: [
                for (final category in kAllNoteCategories)
                  GestureDetector(
                    onTap: () async {
                      await _notes.updateEditedNote(
                        noteId: note.noteId,
                        title: note.title,
                        cleanBody: note.cleanBody,
                        category: category,
                        priority: note.priority,
                        extractedDate: note.extractedDate,
                      );
                      if (context.mounted) {
                        Navigator.of(context).pop();
                      }
                    },
                    child: GlassPane(
                      level: 3,
                      radius: 12,
                      tintOverride: categoryColor(
                        category,
                      ).withValues(alpha: context.isDark ? 0.07 : 0.045),
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 8,
                      ),
                      child: Text(
                        categoryLabel(category),
                        style: TextStyle(
                          color: categoryColor(category),
                          fontWeight: FontWeight.w600,
                          fontSize: 12,
                        ),
                      ),
                    ),
                  ),
              ],
            ),
          ),
        );
      },
    );
  }

  Future<void> _openEditSheet(Note note) async {
    final titleController = TextEditingController(text: note.title);
    final bodyController = TextEditingController(text: note.cleanBody);

    var selectedCategory = note.category;
    var selectedPriority = note.priority;
    DateTime? selectedDate = note.extractedDate;

    await showModalBottomSheet<void>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      barrierColor: Colors.black.withValues(alpha: 0.22),
      builder: (context) {
        return StatefulBuilder(
          builder: (context, setSheetState) {
            return Padding(
              padding: EdgeInsets.fromLTRB(
                14,
                12,
                14,
                14 + MediaQuery.of(context).viewInsets.bottom,
              ),
              child: GlassPane(
                level: 1,
                radius: 22,
                padding: const EdgeInsets.fromLTRB(14, 12, 14, 14),
                child: SingleChildScrollView(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      const Text(
                        'Edit note',
                        style: TextStyle(
                          fontSize: 16,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                      const SizedBox(height: 10),
                      TextField(
                        controller: titleController,
                        decoration: const InputDecoration(
                          labelText: 'Title',
                          isDense: true,
                        ),
                      ),
                      const SizedBox(height: 10),
                      TextField(
                        controller: bodyController,
                        minLines: 3,
                        maxLines: 6,
                        decoration: const InputDecoration(
                          labelText: 'Body',
                          alignLabelWithHint: true,
                        ),
                      ),
                      const SizedBox(height: 10),
                      DropdownButtonFormField<NoteCategory>(
                        initialValue: selectedCategory,
                        decoration: const InputDecoration(
                          labelText: 'Category',
                          isDense: true,
                        ),
                        items: kAllNoteCategories
                            .map(
                              (c) => DropdownMenuItem(
                                value: c,
                                child: Text(categoryLabel(c)),
                              ),
                            )
                            .toList(),
                        onChanged: (value) {
                          if (value == null) return;
                          setSheetState(() {
                            selectedCategory = value;
                          });
                        },
                      ),
                      const SizedBox(height: 10),
                      DropdownButtonFormField<NotePriority>(
                        initialValue: selectedPriority,
                        decoration: const InputDecoration(
                          labelText: 'Priority',
                          isDense: true,
                        ),
                        items: NotePriority.values
                            .map(
                              (p) => DropdownMenuItem(
                                value: p,
                                child: Text(p.name),
                              ),
                            )
                            .toList(),
                        onChanged: (value) {
                          if (value == null) return;
                          setSheetState(() {
                            selectedPriority = value;
                          });
                        },
                      ),
                      const SizedBox(height: 10),
                      Row(
                        children: [
                          Expanded(
                            child: Text(
                              selectedDate == null
                                  ? 'No extracted date'
                                  : (selectedDate!
                                        .toIso8601String()
                                        .split('T')
                                        .first),
                              style: const TextStyle(
                                fontSize: 13,
                                color: Color(0xFF374151),
                              ),
                            ),
                          ),
                          TextButton(
                            onPressed: () async {
                              final now = DateTime.now();
                              final picked = await showDatePicker(
                                context: context,
                                initialDate: selectedDate ?? now,
                                firstDate: DateTime(now.year - 5),
                                lastDate: DateTime(now.year + 10),
                              );
                              if (picked == null) return;
                              setSheetState(() {
                                selectedDate = picked;
                              });
                            },
                            child: const Text('Pick date'),
                          ),
                          TextButton(
                            onPressed: () {
                              setSheetState(() {
                                selectedDate = null;
                              });
                            },
                            child: const Text('Clear'),
                          ),
                        ],
                      ),
                      const SizedBox(height: 10),
                      Align(
                        alignment: Alignment.centerRight,
                        child: ElevatedButton(
                          onPressed: () async {
                            await _notes.updateEditedNote(
                              noteId: note.noteId,
                              title: titleController.text,
                              cleanBody: bodyController.text,
                              category: selectedCategory,
                              priority: selectedPriority,
                              extractedDate: selectedDate,
                            );
                            await HapticFeedback.lightImpact();
                            if (context.mounted) {
                              final displayTitle =
                                  titleController.text.trim().isNotEmpty
                                  ? titleController.text.trim()
                                  : bodyController.text.trim();
                              sl<CaptureUiController>().notifyExternalRecordingSaved(
                                title: displayTitle.isNotEmpty ? displayTitle : 'Note updated',
                                category: selectedCategory,
                                noteId: note.noteId,
                              );
                              Navigator.of(context).pop();
                            }
                          },
                          child: const Text('Save'),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );
      },
    );
  }
}

