              ),
              Expanded(
                child: StreamBuilder<List<Note>>(
                  stream: _notes.watchActive(),
                  builder: (context, snapshot) {
                    final all = snapshot.data ?? const <Note>[];
                    final query = _queryController.text.trim();

                    final results = query.isEmpty
                        ? all
