    setState(() => _savingTelegram = true);
    try {
      await _users.updateTelegramChatId(chatId);
      setState(() => _telegramChatId = chatId.isEmpty ? null : chatId);
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
