import 'dart:async';

import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:flutter/foundation.dart';
import 'package:google_sign_in/google_sign_in.dart';
import 'package:googleapis/calendar/v3.dart' as gcal;
import 'package:googleapis/tasks/v1.dart' as gtasks;
import 'package:wishperlog/core/storage/isar_note_store.dart';
import 'package:wishperlog/features/sync/data/google_api_client.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note.dart';

class SyncRunResult {
  const SyncRunResult({required this.processed, required this.updated});
  final int processed;
  final int updated;
}

class SyncNoteExternalResult {
  const SyncNoteExternalResult({required this.note, this.noteChanged = false});
  final Note note;
  final bool noteChanged;
}

/// Full bi-directional Google Tasks + Google Calendar sync with
/// strict duplicate prevention using the `gtaskId` and `gcalEventId`
/// fields stored on each [Note].
class ExternalSyncService {
  ExternalSyncService({
    FirebaseAuth? auth,
    FirebaseFirestore? firestore,
    IsarNoteStore? isarNoteStore,
    GoogleSignIn? googleSignIn,
  })  : _auth           = auth      ?? FirebaseAuth.instance,
        _firestore      = firestore ?? FirebaseFirestore.instance,
        _isarNoteStore  = isarNoteStore ?? IsarNoteStore.instance,
        _googleSignIn   = googleSignIn  ??
            GoogleSignIn(scopes: [
              gcal.CalendarApi.calendarScope,
              gtasks.TasksApi.tasksScope,
              'email',
            ]);

  final FirebaseAuth _auth;
  final FirebaseFirestore _firestore;
  final IsarNoteStore _isarNoteStore;
  final GoogleSignIn _googleSignIn;

  // ── Auth helpers ──────────────────────────────────────────────────────────

  Future<bool> ensureGoogleConnected() async {
    try {
      return await _googleSignIn.signInSilently() != null;
    } catch (_) { return false; }
  }

  Future<bool> reconnectGoogle() async {
    try {
      return await _googleSignIn.signIn() != null;
    } catch (_) { return false; }
  }

  Future<Map<String, String>?> _authHeaders() async {
    final account = await _googleSignIn.signInSilently();
    if (account == null) return null;
    return account.authHeaders;
  }

  // ── Primary entry-point ───────────────────────────────────────────────────

  /// Full bi-directional sync: push local → remote + pull remote → local.
  Future<SyncRunResult> syncNow() async {
    final headers = await _authHeaders();
    if (headers == null) {
      debugPrint('[ExternalSync] Not signed in — skipping');
      return const SyncRunResult(processed: 0, updated: 0);
    }

    final client    = HeaderClient(headers);
    final tasksApi  = gtasks.TasksApi(client);
    final calApi    = gcal.CalendarApi(client);

    int processed = 0;
    int updated   = 0;

    try {
      final r1 = await _syncGoogleTasks(tasksApi);
      final r2 = await _syncGoogleCalendar(calApi);
      processed = r1.processed + r2.processed;
      updated   = r1.updated   + r2.updated;
    } finally {
      client.close();
    }

    return SyncRunResult(processed: processed, updated: updated);
  }

  // ─────────────────────────────────────────────────────────────────────────
  // GOOGLE TASKS
  // ─────────────────────────────────────────────────────────────────────────

  Future<SyncRunResult> _syncGoogleTasks(gtasks.TasksApi api) async {
    int processed = 0, updated = 0;

    // 1. Pull all remote tasks
    final remoteTasks = await _fetchAllGoogleTasks(api);
    final remoteById  = { for (final t in remoteTasks) if (t.id != null) t.id!: t };

    // 2. Pull all local notes
    final localNotes = await _isarNoteStore.getAllActive();
    final taskNotes  = localNotes.where((n) => n.category == NoteCategory.tasks).toList();

    // Build lookup: gtaskId → local note
    final localByGTaskId = <String, Note>{};
    for (final n in taskNotes) {
      if (n.gtaskId != null) localByGTaskId[n.gtaskId!] = n;
    }

    // 3. PUSH: local task notes → Google Tasks
    for (final note in taskNotes) {
      processed++;
      try {
        if (note.gtaskId == null) {
          // Create new remote task
          final created = await _createGoogleTask(api, note);
          if (created?.id != null) {
            final saved = note.copyWith(gtaskId: created!.id);
            await _isarNoteStore.put(saved);
            await _firestoreUpdate(saved);
            updated++;
            localByGTaskId[created.id!] = saved;
          }
        } else if (remoteById.containsKey(note.gtaskId)) {
          // Update existing remote task if local note is newer
          final remote = remoteById[note.gtaskId!]!;
          // Parse remote.updated (String from API) to DateTime for comparison
          DateTime? remoteUpdated;
          try {
            if (remote.updated != null) {
              remoteUpdated = DateTime.parse(remote.updated!);
            }
          } catch (_) {}

          if (_isLocalNewer(note, remoteUpdated)) {
            await _updateGoogleTask(api, note, remote);
            updated++;
          }
        }
        // (if gtaskId exists but remote has been deleted, clear the id)
        else if (note.gtaskId != null) {
          final cleared = note.copyWith(clearGtaskId: true);
          await _isarNoteStore.put(cleared);
          await _firestoreUpdate(cleared);
        }
      } catch (e) {
        debugPrint('[ExternalSync] Task push error for ${note.noteId}: $e');
      }
    }

    // 4. PULL: remote tasks → local (only those not already linked)
    final uid = _auth.currentUser?.uid ?? 'local_anonymous';
    for (final task in remoteTasks) {
      if (task.id == null || task.title == null) continue;
      processed++;
      if (localByGTaskId.containsKey(task.id!)) {
        // Already linked — sync completion status
        final local = localByGTaskId[task.id!]!;
        if (task.status == 'completed' && local.status != NoteStatus.archived) {
          final archived = local.copyWith(
            status: NoteStatus.archived,
            updatedAt: DateTime.now(),
          );
          await _isarNoteStore.put(archived);
          await _firestoreUpdate(archived);
          updated++;
        }
        continue;
      }
      // New remote task — create local note
      try {
        final note = _googleTaskToNote(task, uid);
        await _isarNoteStore.put(note);
        await _firestoreUpdate(note);
        updated++;
      } catch (e) {
        debugPrint('[ExternalSync] Task pull error for ${task.id}: $e');
      }
    }

    return SyncRunResult(processed: processed, updated: updated);
  }

  Future<List<gtasks.Task>> _fetchAllGoogleTasks(gtasks.TasksApi api) async {
    final all = <gtasks.Task>[];
    String? pageToken;
    do {
      final page = await api.tasks.list(
        '@default',
        showCompleted: true,
        showHidden:    false,
        maxResults:    100,
        pageToken:     pageToken,
      );
      all.addAll(page.items ?? []);
      pageToken = page.nextPageToken;
    } while (pageToken != null);
    return all;
  }

  Future<gtasks.Task?> _createGoogleTask(gtasks.TasksApi api, Note note) async {
    final task = gtasks.Task()
      ..title = note.title
      ..notes = note.cleanBody
      ..status = 'needsAction';

    if (note.extractedDate != null) {
      task.due = note.extractedDate!.toUtc().toIso8601String();
    }
    return api.tasks.insert(task, '@default');
  }

  Future<void> _updateGoogleTask(
      gtasks.TasksApi api, Note note, gtasks.Task remote) async {
    remote
      ..title  = note.title
      ..notes  = note.cleanBody
      ..status = note.status == NoteStatus.archived ? 'completed' : 'needsAction';
    if (note.extractedDate != null) {
      remote.due = note.extractedDate!.toUtc().toIso8601String();
    }
    await api.tasks.update(remote, '@default', remote.id!);
  }

  Note _googleTaskToNote(gtasks.Task task, String uid) {
    final now = DateTime.now();
    DateTime? due;
    if (task.due != null) {
      try { due = DateTime.parse(task.due!); } catch (_) {}
    }
    return Note(
      noteId:        'gtask_${task.id}',
      uid:           uid,
      rawTranscript: task.title ?? '',
      title:         task.title ?? 'Untitled Task',
      cleanBody:     task.notes ?? task.title ?? '',
      category:      NoteCategory.tasks,
      priority:      NotePriority.medium,
      extractedDate: due,
      createdAt:     now,
      updatedAt:     now,
      status:        task.status == 'completed'
                         ? NoteStatus.archived
                         : NoteStatus.active,
      aiModel:       'google_tasks_import',
      gtaskId:       task.id,
      gcalEventId:   null,
      source:        CaptureSource.googleTasks,
      syncedAt:      now,
    );
  }

  // ─────────────────────────────────────────────────────────────────────────
  // GOOGLE CALENDAR
  // ─────────────────────────────────────────────────────────────────────────

  Future<SyncRunResult> _syncGoogleCalendar(gcal.CalendarApi api) async {
    int processed = 0, updated = 0;

    final now        = DateTime.now().toUtc();
    final windowEnd  = now.add(const Duration(days: 60));

    // 1. Pull remote events (next 60 days)
    final remoteEvents = await _fetchCalendarEvents(api, now, windowEnd);
    final remoteById   = { for (final e in remoteEvents) if (e.id != null) e.id!: e };

    // 2. Local notes with dates and no gcalEventId → PUSH
    final localNotes = await _isarNoteStore.getAllActive();
    final datedNotes = localNotes.where((n) =>
        n.extractedDate != null &&
        n.extractedDate!.isAfter(now) &&
        (n.category == NoteCategory.reminders ||
         n.category == NoteCategory.tasks      ||
         n.category == NoteCategory.followUp)).toList();

    final localByGCalId = <String, Note>{};
    for (final n in localNotes) {
      if (n.gcalEventId != null) localByGCalId[n.gcalEventId!] = n;
    }

    for (final note in datedNotes) {
      processed++;
      try {
        if (note.gcalEventId == null) {
          final created = await _createCalendarEvent(api, note);
          if (created?.id != null) {
            final saved = note.copyWith(gcalEventId: created!.id);
            await _isarNoteStore.put(saved);
            await _firestoreUpdate(saved);
            updated++;
            localByGCalId[created.id!] = saved;
          }
        } else if (remoteById.containsKey(note.gcalEventId)) {
          final remote = remoteById[note.gcalEventId!]!;
          // remote.updated is already a DateTime?, pass it directly (no toDateTime())
          if (_isLocalNewer(note, remote.updated)) {
            await _updateCalendarEvent(api, note, remote);
            updated++;
          }
        } else {
          // Remote event was deleted — clear local link
          final cleared = note.copyWith(clearGcalEventId: true);
          await _isarNoteStore.put(cleared);
          await _firestoreUpdate(cleared);
        }
      } catch (e) {
        debugPrint('[ExternalSync] Calendar push error for ${note.noteId}: $e');
      }
    }

    // 3. Pull remote events → local (only new ones)
    final uid = _auth.currentUser?.uid ?? 'local_anonymous';
    for (final event in remoteEvents) {
      if (event.id == null || event.summary == null) continue;
      processed++;
      if (localByGCalId.containsKey(event.id!)) continue;

      try {
        final note = _calendarEventToNote(event, uid);
        await _isarNoteStore.put(note);
        await _firestoreUpdate(note);
        updated++;
      } catch (e) {
        debugPrint('[ExternalSync] Calendar pull error for ${event.id}: $e');
      }
    }

    return SyncRunResult(processed: processed, updated: updated);
  }

  Future<List<gcal.Event>> _fetchCalendarEvents(
      gcal.CalendarApi api, DateTime from, DateTime to) async {
    final all = <gcal.Event>[];
    String? pageToken;
    do {
      final page = await api.events.list(
        'primary',
        timeMin:   from,
        timeMax:   to,
        singleEvents: true,
        orderBy:      'startTime',
        maxResults:   250,
        pageToken:    pageToken,
      );
      all.addAll(page.items ?? []);
      pageToken = page.nextPageToken;
    } while (pageToken != null);
    return all;
  }

  Future<gcal.Event?> _createCalendarEvent(gcal.CalendarApi api, Note note) async {
    final date     = note.extractedDate!.toUtc();
    final endDate  = date.add(const Duration(hours: 1));
    final event    = gcal.Event()
      ..summary     = note.title
      ..description = note.cleanBody
      ..start       = gcal.EventDateTime(dateTime: date,    timeZone: 'UTC')
      ..end         = gcal.EventDateTime(dateTime: endDate, timeZone: 'UTC');
    return api.events.insert(event, 'primary');
  }

  Future<void> _updateCalendarEvent(
      gcal.CalendarApi api, Note note, gcal.Event remote) async {
    final date    = note.extractedDate!.toUtc();
    final endDate = date.add(const Duration(hours: 1));
    remote
      ..summary     = note.title
      ..description = note.cleanBody
      ..start       = gcal.EventDateTime(dateTime: date,    timeZone: 'UTC')
      ..end         = gcal.EventDateTime(dateTime: endDate, timeZone: 'UTC');
    await api.events.update(remote, 'primary', remote.id!);
  }

  Note _calendarEventToNote(gcal.Event event, String uid) {
    final now   = DateTime.now();
    DateTime? start;
    try {
      // Try dateTime first (events with specific times)
      start = event.start?.dateTime?.toLocal();
      // Fallback to date field (all-day events or date-only)
      if (start == null && event.start?.date != null) {
        try {
          // Handle both String and DateTime types for date field
          final dateValue = event.start!.date;
          if (dateValue is DateTime) {
            start = dateValue;
          } else {
            start = DateTime.parse(dateValue.toString());
          }
        } catch (_) {}
      }
    } catch (_) {}

    return Note(
      noteId:        'gcal_${event.id}',
      uid:           uid,
      rawTranscript: event.summary ?? '',
      title:         event.summary ?? 'Untitled Event',
      cleanBody:     event.description ?? event.summary ?? '',
      category:      NoteCategory.reminders,
      priority:      NotePriority.medium,
      extractedDate: start,
      createdAt:     now,
      updatedAt:     now,
      status:        NoteStatus.active,
      aiModel:       'gcal_import',
      gtaskId:       null,
      gcalEventId:   event.id,
      source:        CaptureSource.googleCalendar,
      syncedAt:      now,
    );
  }

  // – Sync a single note to external services (Google Tasks/Calendar) ────────

  /// Syncs a single note with external services (Google Tasks/Calendar).
  /// Returns the note (potentially with updated gtaskId/gcalEventId) and a 
  /// flag indicating if any changes were made.
  Future<SyncNoteExternalResult> syncExternalForNote(Note note) async {
    final headers = await _authHeaders();
    if (headers == null) {
      // Not signed in — just return the note unchanged
      return SyncNoteExternalResult(note: note, noteChanged: false);
    }

    var updatedNote = note;
    var changed = false;

    try {
      final client = HeaderClient(headers);
      try {
        // Attempt to sync to Google Tasks if it's a task/reminder
        if ((note.category == NoteCategory.tasks || 
             note.category == NoteCategory.reminders) &&
            note.gtaskId == null) {
          final tasksApi = gtasks.TasksApi(client);
          final created = await _createGoogleTask(tasksApi, note);
          if (created?.id != null) {
            updatedNote = note.copyWith(gtaskId: created!.id);
            changed = true;
          }
        }

        // Attempt to sync to Google Calendar if dated and applicable
        if ((note.extractedDate != null &&
             (note.category == NoteCategory.reminders ||
              note.category == NoteCategory.tasks ||
              note.category == NoteCategory.followUp)) &&
            updatedNote.gcalEventId == null) {
          final calApi = gcal.CalendarApi(client);
          final created = await _createCalendarEvent(calApi, updatedNote);
          if (created?.id != null) {
            updatedNote = updatedNote.copyWith(gcalEventId: created!.id);
            changed = true;
          }
        }

        // Update Firestore if any external IDs were set
        if (changed) {
          await _firestoreUpdate(updatedNote);
        }
      } finally {
        client.close();
      }
    } catch (e) {
      debugPrint('[ExternalSync] syncExternalForNote error: $e');
      // On error, just return the note unchanged
    }

    return SyncNoteExternalResult(note: updatedNote, noteChanged: changed);
  }

  // ── Completions poll (called from WorkManager / settings) ─────────────────

  Future<int> syncGoogleTaskCompletions() async {
    final headers = await _authHeaders();
    if (headers == null) return 0;
    final client   = HeaderClient(headers);
    final tasksApi = gtasks.TasksApi(client);
    try {
      final result = await _syncGoogleTasks(tasksApi);
      return result.updated;
    } finally {
      client.close();
    }
  }

  // ── Utilities ─────────────────────────────────────────────────────────────

  bool _isLocalNewer(Note note, DateTime? remoteUpdated) {
    if (remoteUpdated == null) return true;
    return note.updatedAt.isAfter(remoteUpdated);
  }

  Future<void> _firestoreUpdate(Note note) async {
    final user = _auth.currentUser;
    if (user == null) return;
    try {
      await _firestore
          .collection('users')
          .doc(user.uid)
          .collection('notes')
          .doc(note.noteId)
          .set(note.toFirestoreJson(), SetOptions(merge: true));
    } catch (e) {
      debugPrint('[ExternalSync] Firestore update failed: $e');
    }
  }
}

import 'dart:async';

import 'package:firebase_core/firebase_core.dart';
import 'package:firebase_messaging/firebase_messaging.dart';
import 'package:flutter/foundation.dart';
import 'package:wishperlog/features/auth/data/repositories/user_repository.dart';
import 'package:wishperlog/features/sync/data/firestore_note_sync_service.dart';
import 'package:wishperlog/firebase_options.dart';

bool _fcmBackgroundHandlerRegistered = false;

void ensureFcmBackgroundHandlerRegistered() {
  if (_fcmBackgroundHandlerRegistered) {
    return;
  }
  FirebaseMessaging.onBackgroundMessage(firebaseMessagingBackgroundHandler);
  _fcmBackgroundHandlerRegistered = true;
}

class FcmSyncService {
  FcmSyncService({
    FirebaseMessaging? messaging,
    UserRepository? users,
    FirestoreNoteSyncService? noteSync,
  }) : _messaging = messaging ?? FirebaseMessaging.instance,
       _users = users ?? UserRepository(),
       _noteSync = noteSync ?? FirestoreNoteSyncService();

  final FirebaseMessaging _messaging;
  final UserRepository _users;
  final FirestoreNoteSyncService _noteSync;

  bool _initialized = false;
  StreamSubscription<String>? _tokenRefreshSub;
  StreamSubscription<RemoteMessage>? _messageSub;
  StreamSubscription<RemoteMessage>? _messageOpenedSub;

  Future<void> initialize() async {
    ensureFcmBackgroundHandlerRegistered();

    if (_initialized) {
      return;
    }
    _initialized = true;

    // Android 13+ and iOS require runtime notification permission.
    try {
      final current = await _messaging.getNotificationSettings();

      if (current.authorizationStatus == AuthorizationStatus.notDetermined) {
        final requested = await requestPermission();
        debugPrint(
          '[FcmSyncService] Notification permission requested: ${requested.authorizationStatus.name}',
        );
      } else {
        debugPrint(
          '[FcmSyncService] Notification permission status: ${current.authorizationStatus.name}',
        );
      }
    } catch (e) {
      debugPrint('[FcmSyncService] Notification permission check error: $e');
    }

    try {
      debugPrint('[FcmSyncService] Getting FCM token...');
      final token = await _messaging.getToken().timeout(
        const Duration(seconds: 5),
        onTimeout: () {
          debugPrint('[FcmSyncService] Token retrieval timed out');
          return null;
        },
      );
      if (token != null && token.isNotEmpty) {
        debugPrint('[FcmSyncService] Got token, updating user...');
        await _users.updateFcmToken(token).timeout(
          const Duration(seconds: 5),
          onTimeout: () {
            debugPrint('[FcmSyncService] Token update timed out');
            return;
          },
        );
      }
    } catch (e) {
      debugPrint('[FcmSyncService] Error getting token: $e');
    }

    _tokenRefreshSub ??= _messaging.onTokenRefresh.listen((token) async {
      await _users.updateFcmToken(token);
    });

    _messageSub ??= FirebaseMessaging.onMessage.listen(_handleRemoteMessage);
    _messageOpenedSub ??= FirebaseMessaging.onMessageOpenedApp.listen(
      _handleRemoteMessage,
    );
  }

  Future<NotificationSettings> requestPermission() {
    return _messaging.requestPermission(
      alert: true,
      announcement: false,
      badge: true,
      carPlay: false,
      criticalAlert: false,
      provisional: false,
      sound: true,
    );
  }

  Future<NotificationSettings> getNotificationSettings() {
    return _messaging.getNotificationSettings();
  }

  Future<void> dispose() async {
    await _tokenRefreshSub?.cancel();
    await _messageSub?.cancel();
    await _messageOpenedSub?.cancel();
    _tokenRefreshSub = null;
    _messageSub = null;
    _messageOpenedSub = null;
    _initialized = false;
  }

  Future<void> _handleRemoteMessage(RemoteMessage message) async {
    debugPrint(
      '[FcmSyncService] Received message: id=${message.messageId}, dataKeys=${message.data.keys.toList()}',
    );

    final type = message.data['type'];
    final noteId = message.data['note_id'];
    final status = message.data['status'];

    if (type == 'note_status_changed' &&
        noteId is String &&
        noteId.trim().isNotEmpty &&
        status is String) {
      await _noteSync.applyStatusFromPush(noteId: noteId, status: status);
      return;
    }

    if (type == 'note_updated' &&
        noteId is String &&
        noteId.trim().isNotEmpty) {
      await _noteSync.syncNoteById(noteId);
    }
  }
}

@pragma('vm:entry-point')
Future<void> firebaseMessagingBackgroundHandler(RemoteMessage message) async {
  try {
    if (Firebase.apps.isEmpty) {
      await Firebase.initializeApp(
        options: DefaultFirebaseOptions.currentPlatform,
      );
    }
    final noteSync = FirestoreNoteSyncService();

    final type = message.data['type'];
    final noteId = message.data['note_id'];
    final status = message.data['status'];

    if (type == 'note_status_changed' &&
        noteId is String &&
        noteId.trim().isNotEmpty &&
        status is String) {
      await noteSync.applyStatusFromPush(noteId: noteId, status: status);
      return;
    }

    if (type == 'note_updated' &&
        noteId is String &&
        noteId.trim().isNotEmpty) {
      await noteSync.syncNoteById(noteId);
    }
  } catch (error) {
    debugPrint('FCM background handler error: $error');
  }
}

import 'dart:async';

import 'package:cloud_firestore/cloud_firestore.dart';
import 'package:firebase_auth/firebase_auth.dart';
import 'package:flutter/foundation.dart';
import 'package:wishperlog/core/storage/isar_note_store.dart';
import 'package:wishperlog/shared/models/note.dart';
import 'package:wishperlog/shared/models/note_helpers.dart';

class FirestoreNoteSyncService {
  FirestoreNoteSyncService({
    FirebaseAuth? auth,
    FirebaseFirestore? firestore,
    IsarNoteStore? isarNoteStore,
  }) : _auth = auth ?? FirebaseAuth.instance,
       _firestore = firestore ?? FirebaseFirestore.instance,
       _isarNoteStore = isarNoteStore ?? IsarNoteStore.instance;

  final FirebaseAuth _auth;
  final FirebaseFirestore _firestore;
  final IsarNoteStore _isarNoteStore;

  bool _started = false;
  bool _isRestarting = false;
  StreamSubscription<User?>? _authSub;
  StreamSubscription<QuerySnapshot<Map<String, dynamic>>>? _noteSub;

  Future<void> start() async {
    if (_started) {
      return;
    }
    _started = true;

    _authSub = _auth.authStateChanges().listen(
      (user) {
        _attachUserListener(user);
      },
      onError: (Object error, StackTrace st) {
        debugPrint('[FirestoreNoteSyncService] Auth stream error: $error');
        debugPrintStack(stackTrace: st);
      },
    );

    await _attachUserListener(_auth.currentUser);
  }

  Future<void> stop() async {
    _started = false;
    await _noteSub?.cancel();
    await _authSub?.cancel();
    _noteSub = null;
    _authSub = null;
  }

  Future<void> _attachUserListener(User? user) async {
    await _noteSub?.cancel();
    _noteSub = null;

    final uid = user?.uid.trim() ?? '';
    if (uid.isEmpty) {
      debugPrint(
        '[FirestoreNoteSyncService] No authenticated user, listener idle',
      );
      return;
    }

    _noteSub = _firestore
        .collection('users')
        .doc(uid)
        .collection('notes')
        .snapshots()
        .listen(
          (snapshot) async {
            try {
              final notes = snapshot.docs
                  .map(
                    (doc) => Note.fromFirestoreJson(
                      doc.data(),
                      uid: uid,
                      noteId: doc.id,
                    ),
                  )
                  .toList();
              await _isarNoteStore.putAll(notes);
            } catch (e, st) {
              debugPrint(
                '[FirestoreNoteSyncService] Snapshot process error: $e',
              );
              debugPrintStack(stackTrace: st);
            }
          },
          onError: (Object error, StackTrace st) async {
            debugPrint(
              '[FirestoreNoteSyncService] Snapshot listener error: $error',
            );
            debugPrintStack(stackTrace: st);
            await _restartAfterDelay();
          },
        );
  }

  Future<void> _restartAfterDelay() async {
    if (_isRestarting || !_started) {
      return;
    }
    _isRestarting = true;
    try {
      await Future<void>.delayed(const Duration(seconds: 3));
      if (_started) {
        await _attachUserListener(_auth.currentUser);
      }
    } finally {
      _isRestarting = false;
    }
  }

  Future<void> syncNoteById(String noteId, {String? uid}) async {
    final resolvedUid = uid ?? _auth.currentUser?.uid;
    if (resolvedUid == null || noteId.trim().isEmpty) {
      debugPrint(
        '[FirestoreNoteSyncService] Skipping syncNoteById: uid=$resolvedUid, noteId=$noteId',
      );
      return;
    }

    try {
      debugPrint(
        '[FirestoreNoteSyncService] Starting sync for note: $noteId (uid: $resolvedUid)',
      );

      final snap = await _firestore
          .collection('users')
          .doc(resolvedUid)
          .collection('notes')
          .doc(noteId)
          .get();

      if (!snap.exists) {
        debugPrint(
          '[FirestoreNoteSyncService] Note not found in Firestore: $noteId',
        );
        return;
      }

      final data = snap.data();
      if (data == null) {
        debugPrint('[FirestoreNoteSyncService] Note data is null: $noteId');
        return;
      }

      debugPrint(
        '[FirestoreNoteSyncService] Downloaded note from Firestore: $noteId',
      );

      final parsed = Note.fromFirestoreJson(
        data,
        uid: resolvedUid,
        noteId: noteId,
      );
      await _isarNoteStore.put(parsed);

      debugPrint(
        '[FirestoreNoteSyncService] Saved note to local Isar store: $noteId',
      );
    } catch (e, st) {
      debugPrint('[FirestoreNoteSyncService] ERROR syncing note $noteId: $e');
      debugPrintStack(stackTrace: st);
    }
  }

  Future<void> applyStatusFromPush({
    required String noteId,
    required String status,
  }) async {
    if (noteId.trim().isEmpty) {
      debugPrint(
        '[FirestoreNoteSyncService] Skipping applyStatusFromPush: empty noteId',
      );
      return;
    }

    try {
      debugPrint(
        '[FirestoreNoteSyncService] Applying status "$status" to note: $noteId',
      );

      final nextStatus = parseStatus(status);
      final existing = await _isarNoteStore.getByNoteId(noteId);
      if (existing == null) {
        debugPrint(
          '[FirestoreNoteSyncService] Note not found in local Isar store: $noteId',
        );
        return;
      }

      final updated = existing.copyWith(
        status: nextStatus,
        updatedAt: DateTime.now(),
        syncedAt: DateTime.now(),
      );

      await _isarNoteStore.put(updated);

      debugPrint(
        '[FirestoreNoteSyncService] Applied status change: $noteId → $nextStatus',
      );
    } catch (e, st) {
      debugPrint(
        '[FirestoreNoteSyncService] ERROR applying status to $noteId: $e',
      );
      debugPrintStack(stackTrace: st);
    }
  }
}

import 'package:http/http.dart' as http;

class HeaderClient extends http.BaseClient {
  HeaderClient(this._headers, [http.Client? inner])
      : _inner = inner ?? http.Client();

  final Map<String, String> _headers;
  final http.Client _inner;

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) {
    request.headers.addAll(_headers);
    return _inner.send(request);
  }

  @override
  void close() {
    _inner.close();
    super.close();
  }
}

import 'dart:convert';
import 'dart:math';

import 'package:flutter/foundation.dart';
import 'package:http/http.dart' as http;
import 'package:wishperlog/core/config/app_env.dart';
import 'package:wishperlog/features/search/data/smart_note_search.dart';
import 'package:wishperlog/shared/models/enums.dart';
import 'package:wishperlog/shared/models/note.dart';
import 'package:wishperlog/shared/models/note_helpers.dart';

class TelegramCommandEvent {
  final int updateId;
  final String chatId;
  final int messageId;
  final String command;
  final String commandArgs;
  final String rawText;

  const TelegramCommandEvent({
    required this.updateId,
    required this.chatId,
    required this.messageId,
    required this.command,
    required this.commandArgs,
    required this.rawText,
  });
}

class TelegramUpdateBatch {
  final List<TelegramCommandEvent> events;
  final int nextOffset;

  const TelegramUpdateBatch({required this.events, required this.nextOffset});
}

class TelegramService {
  static const _baseUrl = 'https://api.telegram.org';

  final String _botToken;
  String? _resolvedBotUsername;

  TelegramService({String? botToken})
    : _botToken = botToken ?? AppEnv.telegramBotToken;

  bool get isConfigured => _botToken.isNotEmpty;

  static const List<Map<String, String>> defaultCommands = [
    {'command': 'start', 'description': 'Link and quick welcome'},
    {'command': 'help', 'description': 'Show available commands'},
    {'command': 'status', 'description': 'Show bot connection status'},
    {'command': 'digest', 'description': 'Send priority brief now'},
    {'command': 'top', 'description': 'Show top 3 priorities now'},
    {'command': 'today', 'description': 'Show today summary card'},
    {'command': 'slots', 'description': 'Show configured digest times'},
    {'command': 'stats', 'description': 'Show category + priority stats'},
    {'command': 'find', 'description': 'Search notes by keyword'},
    {'command': 'agenda', 'description': 'Upcoming dated notes'},
    {'command': 'menu', 'description': 'Show quick action panel'},
    {'command': 'focus', 'description': 'Get one focus reminder'},
    {'command': 'nudge', 'description': 'Get a quick motivational nudge'},
    {'command': 'ping', 'description': 'Health check'},
  ];

  Future<String?> resolveBotUsername() async {
    final configured = AppEnv.telegramBotUsername.trim();
    if (configured.isNotEmpty) return configured;
    if (_resolvedBotUsername != null && _resolvedBotUsername!.isNotEmpty) {
      return _resolvedBotUsername;
    }
    if (!isConfigured) return null;

    try {
      final response = await http
          .get(Uri.parse('$_baseUrl/bot$_botToken/getMe'))
          .timeout(const Duration(seconds: 10));
      if (response.statusCode != 200) {
        debugPrint('[TelegramService] getMe failed: ${response.body}');
        return null;
      }
      final data = jsonDecode(response.body) as Map<String, dynamic>;
      final result = data['result'] as Map<String, dynamic>?;
      final username = (result?['username'] ?? '').toString().trim();
      if (username.isEmpty) return null;
      _resolvedBotUsername = username;
      return username;
    } catch (e) {
      debugPrint('[TelegramService] resolveBotUsername error: $e');
      return null;
    }
  }

  Future<bool> registerDefaultCommands() async {
    if (!isConfigured) return false;
    try {
      final response = await http
          .post(
            Uri.parse('$_baseUrl/bot$_botToken/setMyCommands'),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({'commands': defaultCommands}),
          )
          .timeout(const Duration(seconds: 10));

      if (response.statusCode != 200) {
        debugPrint('[TelegramService] setMyCommands failed: ${response.body}');
        return false;
      }
      return true;
    } catch (e) {
      debugPrint('[TelegramService] registerDefaultCommands error: $e');
      return false;
    }
  }

  Future<TelegramUpdateBatch> fetchCommandUpdates({
    int offset = 0,
    int timeoutSeconds = 3,
  }) async {
    if (!isConfigured) {
      return TelegramUpdateBatch(events: const [], nextOffset: offset);
    }

    try {
      final response = await http
          .get(
            Uri.parse(
              '$_baseUrl/bot$_botToken/getUpdates?offset=$offset&timeout=$timeoutSeconds&allowed_updates=["message"]',
            ),
          )
          .timeout(const Duration(seconds: 12));

      if (response.statusCode != 200) {
        debugPrint('[TelegramService] fetchCommandUpdates failed: ${response.body}');
        return TelegramUpdateBatch(events: const [], nextOffset: offset);
      }

      final body = jsonDecode(response.body) as Map<String, dynamic>;
      final raw = (body['result'] as List?) ?? const [];
      final events = <TelegramCommandEvent>[];
      var nextOffset = offset;

      for (final item in raw) {
        final entry = item as Map<String, dynamic>;
        final updateId = entry['update_id'] as int? ?? 0;
        if (updateId >= nextOffset) nextOffset = updateId + 1;

        final msg = entry['message'] as Map<String, dynamic>?;
        final text = (msg?['text'] ?? '').toString().trim();
        if (!text.startsWith('/')) continue;

        final chatId = msg?['chat']?['id']?.toString().trim();
        if (chatId == null || chatId.isEmpty) continue;
        final messageId = (msg?['message_id'] as int?) ?? 0;

        final firstToken = text.split(RegExp(r'\s+')).first;
        final args = text.length > firstToken.length
            ? text.substring(firstToken.length).trim()
            : '';
        var command = firstToken;
        if (command.startsWith('/')) {
          command = command.substring(1);
        }
        if (command.contains('@')) {
          command = command.split('@').first;
        }
        command = command.toLowerCase().trim();
        if (command.isEmpty) continue;

        events.add(
          TelegramCommandEvent(
            updateId: updateId,
            chatId: chatId,
            messageId: messageId,
            command: command,
            commandArgs: args,
            rawText: text,
          ),
        );
      }

      return TelegramUpdateBatch(events: events, nextOffset: nextOffset);
    } catch (e) {
      debugPrint('[TelegramService] fetchCommandUpdates error: $e');
      return TelegramUpdateBatch(events: const [], nextOffset: offset);
    }
  }

  String buildHelpMessage() {
    return [
      '<b>WishperLog Bot Commands</b>',
      '',
      '/start - welcome and quick setup',
      '/help - this command list',
      '/status - linked chat and digest status',
      '/digest - send priority brief now',
      '/top - send top 3 priority notes',
      '/today - today summary card',
      '/slots - your digest time slots',
      '/stats - category and priority stats',
      '/find <query> - smart semantic-ish note search',
      '/agenda - upcoming extracted date timeline',
      '/menu - rich action command panel',
      '/focus - one actionable focus item',
      '/nudge - quick motivation prompt',
      '/ping - bot health check',
    ].join('\n');
  }

  /// Fallback linker for setups without bot backend/webhook.
  /// Polls getUpdates and looks for `/start <token>` then returns chat_id.
  Future<String?> resolveChatIdByStartToken({
    required String token,
    Duration timeout = const Duration(seconds: 90),
  }) async {
    if (!isConfigured || token.trim().isEmpty) return null;

    final deadline = DateTime.now().add(timeout);
    var offset = 0;

    while (DateTime.now().isBefore(deadline)) {
      try {
        final response = await http
            .get(
              Uri.parse(
                '$_baseUrl/bot$_botToken/getUpdates?offset=$offset&timeout=8&allowed_updates=["message"]',
              ),
            )
            .timeout(const Duration(seconds: 12));

        if (response.statusCode != 200) {
          debugPrint('[TelegramService] getUpdates failed: ${response.body}');
          await Future<void>.delayed(const Duration(seconds: 2));
          continue;
        }

        final body = jsonDecode(response.body) as Map<String, dynamic>;
        final updates = (body['result'] as List?) ?? const [];

        for (final update in updates) {
          final entry = update as Map<String, dynamic>;
          final updateId = entry['update_id'] as int? ?? 0;
          if (updateId >= offset) offset = updateId + 1;

          final msg = entry['message'] as Map<String, dynamic>?;
          final text = (msg?['text'] ?? '').toString().trim();
          if (text.isEmpty) continue;

          if (_isMatchingStartToken(text, token)) {
            final chatId = msg?['chat']?['id']?.toString().trim();
            if (chatId != null && chatId.isNotEmpty) {
              return chatId;
            }
          }
        }
      } catch (e) {
        debugPrint('[TelegramService] resolveChatIdByStartToken error: $e');
      }

      await Future<void>.delayed(const Duration(seconds: 2));
    }

    return null;
  }

  bool _isMatchingStartToken(String text, String token) {
    final normalized = text.trim();
    if (!normalized.startsWith('/start')) return false;
    final parts = normalized.split(RegExp(r'\s+'));
    if (parts.length < 2) return false;
    return parts[1].trim() == token.trim();
  }

  Future<bool> sendDailyDigest({
    required String chatId,
    required List<Note> notes,
    required DateTime localDate,
    int maxItems = 3,
    bool topPriorityOnly = true,
    bool includeMediumFallback = true,
  }) async {
    final text = buildDailyDigestMessage(
      notes: notes,
      localDate: localDate,
      maxItems: maxItems,
