  Future<bool> sendScheduleSlots({
    required String chatId,
    required List<String> slots,
  }) {
    final rows = slots.isEmpty ? ['(none)'] : slots.map((s) => '- $s').toList();
    return sendMessage(
      chatId: chatId,
      text: [
        '<b>Digest Time Slots</b>',
        '<pre>${rows.join('\n')}</pre>',
      ].join('\n'),
